def send_batch(messages):
    """Send up to 10 messages in a single SQS batch."""
    entries = []
    for i, msg in enumerate(messages):
        body = {
            "prompt": msg["prompt"],
            "category": msg["category"],
            "topic_id": str(uuid.uuid4()),
            "target_duration": 90,
        }
        entries.append({
            "Id": str(i),
            "MessageBody": json.dumps(body),
        })
    resp = sqs.send_message_batch(QueueUrl=QUEUE_URL, Entries=entries)
    failed = resp.get("Failed", [])
    if failed:
        print(f"  ⚠ {len(failed)} failed: {failed}")
    return len(entries) - len(failed)

def main():
    print(f"Sending {len(TOPICS)} topics to SQS...")
    total_sent = 0
    for start in range(0, len(TOPICS), 10):
        batch = TOPICS[start : start + 10]
        sent = send_batch(batch)
        total_sent += sent
        print(f"  Batch {start // 10 + 1}: sent {sent}/{len(batch)} (total: {total_sent})")
    print(f"\nDone! {total_sent}/{len(TOPICS)} topics sent to SQS.")

if __name__ == "__main__":
    main()
